try {
  let data = $input.first().json;
  let payload = data.body || data;
  if (!payload) payload = {};

  const roleTitle = payload.role_title || "Unknown Role";
  const experienceLevel = payload.experience_level || "Not specified";
  let skillsText = "Not specified";

  if (Array.isArray(payload.skills)) {
    skillsText = payload.skills.join(', ');
  } else if (typeof payload.skills === 'string') {
    skillsText = payload.skills;
  }

  const prompt = `You are a professional HR recruiter. Write a concise, compelling Job Description for the following role.\n\nRole: ${roleTitle}\nExperience Level: ${experienceLevel}\nRequired Skills: ${skillsText}\n\nThe JD must include:\n1. Role Overview (2-3 sentences)\n2. Key Responsibilities (5 bullet points)\n3. Required Skills and Qualifications\n4. What We Offer (3 bullet points)\n\nKeep the tone professional and engaging. Return plain text only.`;

  return [{
    json: {
      assessment_id: payload.assessment_id || null,
      jid: payload.jid || null,
      role_title: roleTitle,
      skills: payload.skills || null,
      experience_level: experienceLevel,
      jdPrompt: prompt
    }
  }];
} catch (error) {
  return [{
    json: {
      error: error.message || "Unknown error in Build JD Prompt",
      jdPrompt: "Error formatting prompt"
    }
  }];
}

try {
  const aiResponse = $input.first().json;
  const prevItems = $('Build JD Prompt').all();
  const prev = prevItems.length > 0 && prevItems[0].json ? prevItems[0].json : {};
  const webhookItems = $('Webhook').all();
  const wb = webhookItems.length > 0 && webhookItems[0].json && webhookItems[0].json.body ? webhookItems[0].json.body : (webhookItems.length > 0 ? webhookItems[0].json : {});

  let jdText = "";
  if (aiResponse && aiResponse.text) {
    jdText = aiResponse.text;
  } else if (aiResponse && aiResponse.choices && aiResponse.choices.length > 0) {
    jdText = aiResponse.choices[0].message.content;
  } else if (aiResponse && aiResponse.error) {
    jdText = `API Error: ${aiResponse.error.message || 'Unknown error'}`;
  } else {
    jdText = typeof aiResponse === 'string' ? aiResponse : JSON.stringify(aiResponse);
  }

  return [{
    json: {
      assessment_id: prev.assessment_id || wb.assessment_id || null,
      jid: prev.jid || wb.jid || null,
      job_description: (jdText || "").trim()
    }
  }];
} catch (error) {
  return [{
    json: {
      error: error.message || "Unknown error in Parse JD Output",
      job_description: "Failed to parse job description."
    }
  }];
}
